import{_ as t,o as a,c as n,a2 as i}from"./chunks/framework.OWFDNrRT.js";const g=JSON.parse('{"title":"ADR-001: Agent-Driven Development Model","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-001-agent-driven-development.md","filePath":"adr/ADR-001-agent-driven-development.md","lastUpdated":1773460793000}'),s={name:"adr/ADR-001-agent-driven-development.md"};function l(o,e,r,d,c,p){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-001-agent-driven-development-model" tabindex="-1">ADR-001: Agent-Driven Development Model <a class="header-anchor" href="#adr-001-agent-driven-development-model" aria-label="Permalink to &quot;ADR-001: Agent-Driven Development Model&quot;">​</a></h1><p><strong>Status</strong>: Accepted <strong>Date</strong>: 2026-03-09 <strong>Deciders</strong>: kooshapari</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>DINOForge is built entirely through agent-driven development. No human reads or reviews code directly. The human acts as product owner, tester, design director, and failure reporter.</p><p>This means the codebase cannot depend on &quot;smart coding&quot; or human intuition. It must depend on rigid structure, typed interfaces, machine-checkable contracts, and strong observability.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>All development follows an agent-first model:</p><ol><li><strong>Architect agents</strong> define contracts, registries, schemas, extension points</li><li><strong>Runtime agents</strong> handle low-level ECS/hook work</li><li><strong>Pack agents</strong> create content packs from schemas</li><li><strong>Validation agents</strong> run tests, static checks, pack compilation, compatibility</li><li><strong>Diagnosis agents</strong> interpret logs/crashes/failures</li><li><strong>Governance agents</strong> keep abstractions clean, kill duplication</li></ol><h3 id="agent-constraints" tabindex="-1">Agent Constraints <a class="header-anchor" href="#agent-constraints" aria-label="Permalink to &quot;Agent Constraints&quot;">​</a></h3><p>Agents MUST:</p><ul><li>Work through manifests</li><li>Use generators/templates</li><li>Update docs/contracts</li><li>Add tests for new public surfaces</li><li>Log failure modes</li><li>Keep features pack-based when possible</li></ul><p>Agents MUST NOT:</p><ul><li>Patch runtime internals unless assigned runtime-layer work</li><li>Invent new registry patterns casually</li><li>Duplicate schemas</li><li>Bypass validators</li><li>Hardcode content IDs in engine glue</li><li>Add undocumented extension points</li><li>Skip tests</li></ul><h3 id="legal-move-classes" tabindex="-1">Legal Move Classes <a class="header-anchor" href="#legal-move-classes" aria-label="Permalink to &quot;Legal Move Classes&quot;">​</a></h3><p>All agent work must reduce to one of:</p><ul><li>create schema</li><li>extend registry</li><li>add content pack</li><li>patch mapping</li><li>write validator</li><li>add test fixture</li><li>add debug view</li><li>add migration</li><li>add compatibility rule</li><li>add documentation manifest</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Every module needs strict ownership boundaries, public interfaces, generated docs, examples, invariants, self-tests, fixtures, expected logs, failure modes, rollback behavior</li><li>Every folder needs purpose, allowed imports, patterns agents may/may not use</li><li>Every feature needs design manifest, schema, sample usage, tests, observability hooks</li><li>The CLAUDE.md file serves as the primary agent governance document</li></ul>',18)])])}const m=t(s,[["render",l]]);export{g as __pageData,m as default};
